[{"text": "\"\"\"P Machine Simulator for interactive development.\"\"\"\n\nfrom typing import Dict, Any, List, Optional, Set\nfrom pydantic import BaseModel, Field\nimport json\n\nclass SimulateMachineParams(BaseModel):\n    \"\"\"Parameters for machine simulation\"\"\"\n    machine_code: str = Field(..., description=\"P machine code to simulate\")\n    initial_event: Optional[str] = Field(None, description=\"Initial event to send\")\n    event_sequence: Optional[List[Dict[str, Any]]] = Field(\n        None, \n        description=\"Sequence of events to simulate: [{event: 'eName', payload: {...}}]\"\n    )\n    max_steps: int = Field(100, description=\"Maximum simulation steps\")\n\nclass QueryMachineStateParams(BaseModel):\n    \"\"\"Parameters for querying machine state during simulation\"\"\"\n    simulation_id: str = Field(..., description=\"ID of the running simulation\")\n    query: str = Field(..., description=\"What to query: 'current_state', 'variables', 'queue'\")\n\ndef register_simulator_tools(mcp, get_services, with_metadata):\n    \"\"\"Register machine simulation tools.\"\"\"\n    \n    # Store active simulations\n    _simulations: Dict[str, Any] = {}\n    \n    @mcp.tool(\n        name=\"simulate_machine\",\n        description=\"\"\"Simulate a P machine interactively without full compilation.\n        \n        Useful for:\n        - Testing state transitions\n        - Understanding machine behavior\n        - Debugging specific scenarios\n        - Quick prototyping\n        \n        Returns simulation ID for further interaction.\"\"\"\n    )\n    def simulate_machine(params: SimulateMachineParams) -> Dict[str, Any]:\n        import uuid\n        from core.compilation.p_parser import parse_machine_structure\n        \n        sim_id = str(uuid.uuid4())[:8]\n        \n        # Parse machine structure\n        machine_info = parse_machine_structure(params.machine_code)\n        \n        # Initialize simulation state\n        sim_state = {\n            \"machine\": machine_info,\n            \"current_state\": machine_info.get(\"start_state\", \"Init\"),\n            \"variables\": {},\n            \"event_queue\": [],\n            \"trace\": [],\n            \"step_count\": 0\n        }\n        \n        # Initialize variables from machine\n        for var in machine_info.get(\"variables\", []):\n            sim_state[\"variables\"][var[\"name\"]] = _get_default_value(var[\"type\"])\n        \n        # Add initial event if provided\n        if params.initial_event:\n            sim_state[\"event_queue\"].append({\n                \"event\": params.initial_event,\n                \"payload\": {}\n            })\n        \n        # Add event sequence\n        if params.event_sequence:\n            sim_state[\"event_queue\"].extend(params.event_sequence)\n        \n        # Run simulation steps\n        results = []\n        while sim_state[\"event_queue\"] and sim_state[\"step_count\"] < params.max_steps:\n            step_result = _simulate_step(sim_state)\n            results.append(step_result)\n            sim_state[\"step_count\"] += 1\n        \n        # Store simulation for querying\n        _simulations[sim_id] = sim_state\n        \n        return with_metadata(\"simulate_machine\", {\n            \"success\": True,\n            \"simulation_id\": sim_id,\n            \"machine_name\": machine_info.get(\"name\"),\n            \"final_state\": sim_state[\"current_state\"],\n            \"steps_executed\": sim_state[\"step_count\"],\n            \"trace\": results,\n            \"remaining_events\": len(sim_state[\"event_queue\"]),\n            \"hint\": \"Use 'query_simulation' to inspect state or 'send_event_to_simulation' to continue\"\n        })\n    \n    @mcp.tool(\n        name=\"send_event_to_simulation\",\n        description=\"Send an event to a running simulation and see the result\"\n    )\n    def send_event_to_simulation(params: Dict[str, Any]) -> Dict[str, Any]:\n        sim_id = params[\"simulation_id\"]\n        event_name = params[\"event\"]\n        payload = params.get(\"payload\", {})\n        \n        if sim_id not in _simulations:\n            return with_metadata(\"send_event_to_simulation\", {\n                \"success\": False,\n                \"error\": \"Simulation not found\"\n            })\n        \n        sim_state = _simulations[sim_id]\n        \n        # Add event to queue\n        sim_state[\"event_queue\"].append({\n            \"event\": event_name,\n            \"payload\": payload\n        })\n        \n        # Process one step\n        step_result = _simulate_step(sim_state)\n        sim_state[\"step_count\"] += 1\n        \n        return with_metadata(\"send_event_to_simulation\", {\n            \"success\": True,\n            \"simulation_id\": sim_id,\n            \"step_result\": step_result,\n            \"current_state\": sim_state[\"current_state\"],\n            \"variables\": sim_state[\"variables\"],\n            \"queue_length\": len(sim_state[\"event_queue\"])\n        })\n\ndef _get_default_value(type_str: str) -> Any:\n    \"\"\"Get default value for P type.\"\"\"\n    if type_str == \"int\":\n        return 0\n    elif type_str == \"bool\":\n        return False\n    elif type_str == \"string\":\n        return \"\"\n    elif type_str.startswith(\"seq[\"):\n        return []\n    elif type_str.startswith(\"set[\"):\n        return set()\n    elif type_str.startswith(\"map[\"):\n        return {}\n    else:\n        return None\n\ndef _simulate_step(sim_state: Dict[str, Any]) -> Dict[str, Any]:\n    \"\"\"Simulate one step of machine execution.\"\"\"\n    if not sim_state[\"event_queue\"]:\n        return {\"type\": \"idle\", \"message\": \"No events to process\"}\n    \n    # Dequeue event\n    current_event = sim_state[\"event_queue\"].pop(0)\n    current_state = sim_state[\"current_state\"]\n    \n    # Find handler in current state\n    state_info = sim_state[\"machine\"][\"states\"].get(current_state, {})\n    handlers = state_info.get(\"handlers\", {})\n    \n    if current_event[\"event\"] in handlers:\n        handler = handlers[current_event[\"event\"]]\n        \n        # Execute handler actions (simplified)\n        result = {\n            \"type\": \"event_handled\",\n            \"state\": current_state,\n            \"event\": current_event[\"event\"],\n            \"actions\": handler.get(\"actions\", [])\n        }\n        \n        # Handle goto if present\n        if \"goto\" in handler:\n            sim_state[\"current_state\"] = handler[\"goto\"]\n            result[\"transition\"] = handler[\"goto\"]\n        \n        return result\n    else:\n        # Check for deferred/ignored events\n        if current_event[\"event\"] in state_info.get(\"deferred\", []):\n            # Re-queue deferred event\n            sim_state[\"event_queue\"].append(current_event)\n            return {\n                \"type\": \"event_deferred\",\n                \"state\": current_state,\n                \"event\": current_event[\"event\"]\n            }\n        elif current_event[\"event\"] in state_info.get(\"ignored\", []):\n            return {\n                \"type\": \"event_ignored\",\n                \"state\": current_state,\n                \"event\": current_event[\"event\"]\n            }\n        else:\n            return {\n                \"type\": \"unhandled_event\",\n                \"state\": current_state,\n                \"event\": current_event[\"event\"],\n                \"error\": f\"Event {current_event['event']} cannot be handled in state {current_state}\"\n            }", "type": "text"}]